    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        // regular v2 trade
        //
        //     {
        //         "type": "trade",
        //         "symbol": "BTCUSD",
        //         "event_id": 122258166738,
        //         "timestamp": 1655330221424,
        //         "price": "22269.14",
        //         "quantity": "0.00004473",
        //         "side": "buy"
        //     }
        //
        // multi data trade
        //
        //    {
        //        "type": "trade",
        //        "symbol": "ETHUSD",
        //        "tid": "1683002242170204", // this is not TS, but somewhat ID
        //        "price": "2299.24",
        //        "amount": "0.002662",
        //        "makerSide": "bid"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "timestamp");
        Object id = this.safeString2(trade, "event_id", "tid");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString2(trade, "quantity", "amount");
        Object side = this.safeStringLower(trade, "side");
        if (Helpers.isTrue(Helpers.isEqual(side, null)))
        {
            Object marketSide = this.safeStringLower(trade, "makerSide");
            if (Helpers.isTrue(Helpers.isEqual(marketSide, "bid")))
            {
                side = "sell";
            } else if (Helpers.isTrue(Helpers.isEqual(marketSide, "ask")))
            {
                side = "buy";
            }
        }
        Object marketId = this.safeStringLower(trade, "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        final Object finalSide = side;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", null );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", GeminiCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "cost", null );
            put( "amount", amountString );
            put( "fee", null );
        }}, market);
    }

